package integration

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"net/http/httptest"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	errs "go.flipt.io/flipt/errors"
	"go.flipt.io/flipt/internal/server/evaluation"
	"go.flipt.io/flipt/internal/storage"
	"go.flipt.io/flipt/rpc/flipt"
	rpcevaluation "go.flipt.io/flipt/rpc/flipt/evaluation"
	"go.uber.org/zap/zaptest"
	"google.golang.org/grpc"
	"google.golang.org/protobuf/encoding/protojson"
	"google.golang.org/protobuf/types/known/timestamppb"
)

// mockStore implements the evaluation.Storer interface for testing.
type mockStore struct {
	flags           map[string]*flipt.Flag
	rules           map[string][]*storage.EvaluationRule
	distributions   map[string][]*storage.EvaluationDistribution
	rollouts        map[string][]*storage.EvaluationRollout
	getError        error
	getRulesError   error
	getDistError    error
	getRolloutsError error
}

func newMockStore() *mockStore {
	return &mockStore{
		flags:         make(map[string]*flipt.Flag),
		rules:         make(map[string][]*storage.EvaluationRule),
		distributions: make(map[string][]*storage.EvaluationDistribution),
		rollouts:      make(map[string][]*storage.EvaluationRollout),
	}
}

func (m *mockStore) GetFlag(ctx context.Context, req storage.ResourceRequest) (*flipt.Flag, error) {
	if m.getError != nil {
		return nil, m.getError
	}
	key := req.Namespace() + "/" + req.Key()
	flag, ok := m.flags[key]
	if !ok {
		return nil, errs.ErrNotFound(fmt.Sprintf("flag %s not found", req.Key()))
	}
	return flag, nil
}

func (m *mockStore) GetEvaluationRules(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRule, error) {
	if m.getRulesError != nil {
		return nil, m.getRulesError
	}
	key := req.Namespace() + "/" + req.Key()
	return m.rules[key], nil
}

func (m *mockStore) GetEvaluationDistributions(ctx context.Context, req storage.IDRequest) ([]*storage.EvaluationDistribution, error) {
	if m.getDistError != nil {
		return nil, m.getDistError
	}
	return m.distributions[req.ID()], nil
}

func (m *mockStore) GetEvaluationRollouts(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRollout, error) {
	if m.getRolloutsError != nil {
		return nil, m.getRolloutsError
	}
	key := req.Namespace() + "/" + req.Key()
	return m.rollouts[key], nil
}

// setupServer creates an evaluation server and returns a test HTTP server.
func setupServer(t *testing.T, store evaluation.Storer) *httptest.Server {
	logger := zaptest.NewLogger(t)
	evalServer := evaluation.New(logger, store)

	// Create a grpc server with the evaluation service
	grpcServer := grpc.NewServer()
	evalServer.RegisterGRPC(grpcServer)

	// Create the HTTP test server with the gRPC server running
	lis, err := net.Listen("tcp", "127.0.0.1:0")
	require.NoError(t, err)

	go grpcServer.Serve(lis)
	t.Cleanup(func() {
		grpcServer.Stop()
		lis.Close()
	})

	// Get the actual address the gRPC server is listening on
	grpcAddr := lis.Addr().String()

	// Create a client connection to the gRPC server
	conn, err := grpc.Dial(
		grpcAddr,
		grpc.WithInsecure(),
		grpc.WithBlock(),
	)
	require.NoError(t, err)
	t.Cleanup(func() {
		conn.Close()
	})

	// Register the gRPC gateway handlers
	mux := grpc.NewMux()
	err = rpcevaluation.RegisterEvaluationServiceHandler(context.Background(), mux, conn)
	require.NoError(t, err)

	// Create HTTP test server
	server := httptest.NewServer(mux)
	t.Cleanup(server.Close)

	return server
}

// TestBooleanEvaluationSuccess tests successful boolean flag evaluation.
func TestBooleanEvaluationSuccess(t *testing.T) {
	store := newMockStore()

	// Setup a boolean flag that is enabled
	store.flags["default/feature-flag"] = &flipt.Flag{
		NamespaceKey: "default",
		Key:          "feature-flag",
		Name:         "Feature Flag",
		Enabled:      true,
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		CreatedAt:    timestamppb.Now(),
		UpdatedAt:    timestamppb.Now(),
	}

	// No rollouts, so it should return the flag's enabled state
	store.rollouts["default/feature-flag"] = []*storage.EvaluationRollout{}

	server := setupServer(t, store)
	defer server.Close()

	req := &rpcevaluation.EvaluationRequest{
		RequestId:    "test-request-1",
		NamespaceKey: "default",
		FlagKey:      "feature-flag",
		EntityId:     "user-123",
		Context: map[string]string{
			"plan": "premium",
		},
	}

	reqBody, err := protojson.Marshal(req)
	require.NoError(t, err)

	resp, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/boolean", server.URL),
		"application/json",
		bytes.NewReader(reqBody),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Check status code
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("expected status 200, got %d", resp.StatusCode)
	}

	// Parse response
	body, err := io.ReadAll(resp.Body)
	require.NoError(t, err)

	var evalResp rpcevaluation.BooleanEvaluationResponse
	err = protojson.Unmarshal(body, &evalResp)
	require.NoError(t, err)

	// Verify response
	assert.True(t, evalResp.Enabled)
	assert.Equal(t, "feature-flag", evalResp.FlagKey)
	assert.Equal(t, "test-request-1", evalResp.RequestId)
	assert.Equal(t, rpcevaluation.EvaluationReason_DEFAULT_EVALUATION_REASON, evalResp.Reason)
}

// TestBooleanEvaluationDisabled tests boolean flag evaluation when flag is disabled.
func TestBooleanEvaluationDisabled(t *testing.T) {
	store := newMockStore()

	// Setup a boolean flag that is disabled
	store.flags["default/feature-flag"] = &flipt.Flag{
		NamespaceKey: "default",
		Key:          "feature-flag",
		Name:         "Feature Flag",
		Enabled:      false,
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		CreatedAt:    timestamppb.Now(),
		UpdatedAt:    timestamppb.Now(),
	}

	// No rollouts
	store.rollouts["default/feature-flag"] = []*storage.EvaluationRollout{}

	server := setupServer(t, store)
	defer server.Close()

	req := &rpcevaluation.EvaluationRequest{
		RequestId:    "test-request-2",
		NamespaceKey: "default",
		FlagKey:      "feature-flag",
		EntityId:     "user-456",
		Context:      map[string]string{},
	}

	reqBody, err := protojson.Marshal(req)
	require.NoError(t, err)

	resp, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/boolean", server.URL),
		"application/json",
		bytes.NewReader(reqBody),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		t.Fatalf("expected status 200, got %d", resp.StatusCode)
	}

	body, err := io.ReadAll(resp.Body)
	require.NoError(t, err)

	var evalResp rpcevaluation.BooleanEvaluationResponse
	err = protojson.Unmarshal(body, &evalResp)
	require.NoError(t, err)

	assert.False(t, evalResp.Enabled)
	assert.Equal(t, "feature-flag", evalResp.FlagKey)
}

// TestVariantEvaluationSuccess tests successful variant flag evaluation.
func TestVariantEvaluationSuccess(t *testing.T) {
	store := newMockStore()

	// Setup a variant flag
	store.flags["default/color-flag"] = &flipt.Flag{
		NamespaceKey: "default",
		Key:          "color-flag",
		Name:         "Color Flag",
		Enabled:      true,
		Type:         flipt.FlagType_VARIANT_FLAG_TYPE,
		CreatedAt:    timestamppb.Now(),
		UpdatedAt:    timestamppb.Now(),
	}

	// No rules, so it should not match
	store.rules["default/color-flag"] = []*storage.EvaluationRule{}

	server := setupServer(t, store)
	defer server.Close()

	req := &rpcevaluation.EvaluationRequest{
		RequestId:    "test-request-3",
		NamespaceKey: "default",
		FlagKey:      "color-flag",
		EntityId:     "user-789",
		Context: map[string]string{
			"region": "us-west",
		},
	}

	reqBody, err := protojson.Marshal(req)
	require.NoError(t, err)

	resp, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/variant", server.URL),
		"application/json",
		bytes.NewReader(reqBody),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		t.Fatalf("expected status 200, got %d", resp.StatusCode)
	}

	body, err := io.ReadAll(resp.Body)
	require.NoError(t, err)

	var evalResp rpcevaluation.VariantEvaluationResponse
	err = protojson.Unmarshal(body, &evalResp)
	require.NoError(t, err)

	assert.Equal(t, "color-flag", evalResp.FlagKey)
	assert.Equal(t, "test-request-3", evalResp.RequestId)
	assert.False(t, evalResp.Match)
}

// TestFlagNotFound tests evaluation when flag does not exist.
func TestFlagNotFound(t *testing.T) {
	store := newMockStore()
	// Don't add any flags to the store

	server := setupServer(t, store)
	defer server.Close()

	req := &rpcevaluation.EvaluationRequest{
		RequestId:    "test-request-4",
		NamespaceKey: "default",
		FlagKey:      "nonexistent-flag",
		EntityId:     "user-999",
		Context:      map[string]string{},
	}

	reqBody, err := protojson.Marshal(req)
	require.NoError(t, err)

	resp, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/boolean", server.URL),
		"application/json",
		bytes.NewReader(reqBody),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Should return error status code (not 200)
	if resp.StatusCode == http.StatusOK {
		t.Fatalf("expected non-200 status, got %d", resp.StatusCode)
	}

	// Verify that error is returned (should be in error details)
	body, err := io.ReadAll(resp.Body)
	require.NoError(t, err)

	// Check that body contains error information
	if len(body) == 0 {
		t.Fatal("expected error response body")
	}
}

// TestInvalidRequestBody tests evaluation with invalid request body.
func TestInvalidRequestBody(t *testing.T) {
	store := newMockStore()
	store.flags["default/feature-flag"] = &flipt.Flag{
