	resp, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/boolean", server.URL),
		"application/json",
		bytes.NewReader(invalidJSON),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Should return error status code
	if resp.StatusCode == http.StatusOK {
		t.Fatalf("expected non-200 status for invalid JSON, got %d", resp.StatusCode)
	}
