		CreatedAt:    timestamppb.Now(),
		UpdatedAt:    timestamppb.Now(),
	}
	store.rollouts["ns2/flag"] = []*storage.EvaluationRollout{}

	server := setupServer(t, store)
	defer server.Close()

	// Evaluate in namespace 1
	req1 := &rpcevaluation.EvaluationRequest{
		RequestId:    "req-ns1",
