		FlagKey:      "flag",
		EntityId:     "user-1",
		Context:      map[string]string{},
	}

	reqBody1, err := protojson.Marshal(req1)
	require.NoError(t, err)

	resp1, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/boolean", server.URL),
		"application/json",
		bytes.NewReader(reqBody1),
	)
	require.NoError(t, err)
	defer resp1.Body.Close()

	if resp1.StatusCode != http.StatusOK {
		t.Fatalf("expected status 200 for ns1, got %d", resp1.StatusCode)
	}

	body1, err := io.ReadAll(resp1.Body)
	require.NoError(t, err)

	var evalResp1 rpcevaluation.BooleanEvaluationResponse
	err = protojson.Unmarshal(body1, &evalResp1)
	require.NoError(t, err)

	assert.True(t, evalResp1.Enabled)

	// Evaluate in namespace 2
	req2 := &rpcevaluation.EvaluationRequest{
		RequestId:    "req-ns2",
		NamespaceKey: "ns2",
		FlagKey:      "flag",
		EntityId:     "user-2",
		Context:      map[string]string{},
	}

	reqBody2, err := protojson.Marshal(req2)
	require.NoError(t, err)

	resp2, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/boolean", server.URL),
		"application/json",
		bytes.NewReader(reqBody2),
	)
	require.NoError(t, err)
	defer resp2.Body.Close()

	if resp2.StatusCode != http.StatusOK {
		t.Fatalf("expected status 200 for ns2, got %d", resp2.StatusCode)
	}

	body2, err := io.ReadAll(resp2.Body)
	require.NoError(t, err)

	var evalResp2 rpcevaluation.BooleanEvaluationResponse
