	assert.NotNil(t, boolResp1)
	assert.True(t, boolResp1.Enabled)
	assert.Equal(t, "flag-1", boolResp1.FlagKey)

	// Check second response (flag-2 disabled)
	if batchResp.Responses[1].Type != rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE {
		t.Fatal("expected boolean response type for second response")
	}

	boolResp2 := batchResp.Responses[1].GetBooleanResponse()
	assert.NotNil(t, boolResp2)
	assert.False(t, boolResp2.Enabled)
	assert.Equal(t, "flag-2", boolResp2.FlagKey)
