// mockStore implements the evaluation.Storer interface for testing.
type mockStore struct {
	flags           map[string]*flipt.Flag
	rules           map[string][]*storage.EvaluationRule
	distributions   map[string][]*storage.EvaluationDistribution
	rollouts        map[string][]*storage.EvaluationRollout
	getError        error
	getRulesError   error
	getDistError    error
	getRolloutsError error
}

func newMockStore() *mockStore {
	return &mockStore{
		flags:         make(map[string]*flipt.Flag),
		rules:         make(map[string][]*storage.EvaluationRule),
		distributions: make(map[string][]*storage.EvaluationDistribution),
		rollouts:      make(map[string][]*storage.EvaluationRollout),
	}
}

func (m *mockStore) GetFlag(ctx context.Context, req storage.ResourceRequest) (*flipt.Flag, error) {
	if m.getError != nil {
		return nil, m.getError
	}
	key := req.Namespace() + "/" + req.Key()
	flag, ok := m.flags[key]
	if !ok {
		return nil, errs.ErrNotFound(fmt.Sprintf("flag %s not found", req.Key()))
	}
	return flag, nil
}

func (m *mockStore) GetEvaluationRules(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRule, error) {
	if m.getRulesError != nil {
		return nil, m.getRulesError
	}
	key := req.Namespace() + "/" + req.Key()
	return m.rules[key], nil
}

func (m *mockStore) GetEvaluationDistributions(ctx context.Context, req storage.IDRequest) ([]*storage.EvaluationDistribution, error) {
	if m.getDistError != nil {
		return nil, m.getDistError
	}
	return m.distributions[req.ID()], nil
}

func (m *mockStore) GetEvaluationRollouts(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRollout, error) {
	if m.getRolloutsError != nil {
		return nil, m.getRolloutsError
	}
	key := req.Namespace() + "/" + req.Key()
	return m.rollouts[key], nil
}

// setupServer creates an evaluation server and returns a test HTTP server.
func setupServer(t *testing.T, store evaluation.Storer) *httptest.Server {
	logger := zaptest.NewLogger(t)
	evalServer := evaluation.New(logger, store)

	// Create a grpc server with the evaluation service
	grpcServer := grpc.NewServer()
	evalServer.RegisterGRPC(grpcServer)

	// Create the HTTP test server with the gRPC server running
	lis, err := net.Listen("tcp", "127.0.0.1:0")
	require.NoError(t, err)

	go grpcServer.Serve(lis)
	t.Cleanup(func() {
		grpcServer.Stop()
		lis.Close()
	})

	// Get the actual address the gRPC server is listening on
	grpcAddr := lis.Addr().String()

	// Create a client connection to the gRPC server
	conn, err := grpc.Dial(
		grpcAddr,
		grpc.WithInsecure(),
		grpc.WithBlock(),
	)
	require.NoError(t, err)
	t.Cleanup(func() {
		conn.Close()
	})

	// Register the gRPC gateway handlers
	mux := grpc.NewMux()
	err = rpcevaluation.RegisterEvaluationServiceHandler(context.Background(), mux, conn)
	require.NoError(t, err)

	// Create HTTP test server
	server := httptest.NewServer(mux)
	t.Cleanup(server.Close)

	return server
}

